def chain_prompts(model, tokenizer, steps):
    """Break complex tasks into simple steps for small models."""
    results = []
    for step in steps:
        messages = [
            {"role": "system", "content": "Answer in one sentence only."},
            {"role": "user", "content": step}
        ]
        text = tokenizer.apply_chat_template(
            messages, tokenize=False, add_generation_prompt=True
        )
        inputs = tokenizer(text, return_tensors="pt").to(model.device)
        output = model.generate(
            **inputs, max_new_tokens=50, temperature=0.3
        )
        result = tokenizer.decode(
            output[0][inputs["input_ids"].shape[-1]:],
            skip_special_tokens=True
        )
        results.append(result)
    return results

steps = [
    "What is the capital of France?",
    "What language do they speak in France?",
    "Write a short greeting in French."
]
for i, r in enumerate(chain_prompts(model, tokenizer, steps)):
    print(f"Step {i+1}: {r}")
